templates.flow_structure:
{
  "nodes": [
    {
      "id": "node-start",
      "type": "custom",
      "data": {
        "label": "Início do Fluxo",
        "type": "start",
        "status": "SUCCESS",
        "config": {}
      }
    },
    {
      "id": "node-gemini",
      "type": "custom",
      "data": {
        "label": "Gerar Landing Page",
        "type": "httpRequest",
        "status": "SUCCESS",
        "config": {
          "url": "https://generativelanguage.googleapis.com/v1beta/models/gemini-3-flash-preview:generateContent?key={YOUR_API_KEY}",
          "method": "POST",
          "body": {
            "contents": [
              {
                "parts": [
                  {
                    "text": "{{prompt}}"
                  }
                ]
              }
            ]
          }
        }
      }
    },
    {
      "id": "node-deploy",
      "type": "custom",
      "data": {
        "label": "Deploy do Site",
        "type": "httpRequest",
        "status": "SUCCESS",
        "config": {
          "url": "https://flowpost.onrender.com/api/upload",
          "method": "POST",
          "body": {
            "name": "{{siteName}}",
            "html": "{{input.text}}"
          }
        }
      }
    }
  ],
  "edges": [
    {
      "id": "e1",
      "source": "node-start",
      "target": "node-gemini"
    },
    {
      "id": "e2",
      "source": "node-gemini",
      "target": "node-deploy"
    }
  ]
}

